/* ASN1T_E2AP_PDU */

ASN1T_E2AP_PDU* new_ASN1T_E2AP_PDU (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_E2AP_PDU));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_E2AP_PDU;
}

ASN1C_E2AP_PDU::ASN1C_E2AP_PDU (ASN1T_E2AP_PDU& data) : 
   ASN1CType(), msgData(data)
{
   setRunTimeKey (_rtkey, sizeof(_rtkey));
}

ASN1C_E2AP_PDU::ASN1C_E2AP_PDU (OSRTMessageBufferIF& msgBuf
   , ASN1T_E2AP_PDU& data) : ASN1CType(msgBuf), msgData(data)
{
   setRunTimeKey (_rtkey, sizeof(_rtkey));
}
ASN1C_E2AP_PDU::ASN1C_E2AP_PDU (OSRTContext &context, ASN1T_E2AP_PDU& data) : 
   ASN1CType(context), msgData(data)
{
   setRunTimeKey (_rtkey, sizeof(_rtkey));
}


ASN1T_E2AP_PDU::~ASN1T_E2AP_PDU ()
{
   OSCTXT* pctxt = mpContext.getCtxtPtr();
   if (pctxt != 0 && !rtxMemHeapIsEmpty (pctxt)) {
      asn1Free_E2AP_PDU (pctxt, this);
   }
}

int ASN1C_E2AP_PDU::EncodeTo (OSRTMessageBufferIF& msgBuf)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   if (msgBuf.isA (OSRTMessageBufferIF::PEREncode)) {
      stat= asn1PE_E2AP_PDU (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PEREncodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONEncode)) {
      return asn1JsonEnc_E2AP_PDU (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int ASN1C_E2AP_PDU::DecodeFrom (OSRTMessageBufferIF& msgBuf, OSBOOL free)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   asn1Init_E2AP_PDU (&msgData, free, getCtxtPtr());
   msgData.setContext (msgBuf.getContext());
   if (msgBuf.isA (OSRTMessageBufferIF::PERDecode)) {
      stat = asn1PD_E2AP_PDU (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PERDecodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONDecode)) {
      return asn1JsonDec_E2AP_PDU (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int asn1Init_E2AP_PDU (ASN1T_E2AP_PDU* pvalue, OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_E2AP_PDU (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_E2AP_PDU (OSCTXT *pctxt, ASN1T_E2AP_PDU* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.initiatingMessage) {
            asn1Free_InitiatingMessage (pctxt, pvalue->u.initiatingMessage);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.initiatingMessage);
            pvalue->u.initiatingMessage = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.successfulOutcome) {
            asn1Free_SuccessfulOutcome (pctxt, pvalue->u.successfulOutcome);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.successfulOutcome);
            pvalue->u.successfulOutcome = 0;
         }
         break;

      case 3:
         if (0 != pvalue->u.unsuccessfulOutcome) {
            asn1Free_UnsuccessfulOutcome (pctxt, pvalue->u.unsuccessfulOutcome);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.unsuccessfulOutcome);
            pvalue->u.unsuccessfulOutcome = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

void ASN1C_E2AP_PDU::MemFree ()
{
   asn1Free_E2AP_PDU (getCtxtPtr(), &msgData);
}

